sys_script_include.script:
var AROPCheckSeeder_DEX = Class.create();
AROPCheckSeeder_DEX.prototype = {
    initialize: function() {},
    getChecks: function() {
        return [{"module":"DEX","check_name":"DEX Device Registration","order":null,"check_script":"(function(checkDef, dateFilter) {    var ga = new GlideAggregate("dex_device");    ga.addAggregate("COUNT");    ga.query();    var count = ga.next() ? parseInt(ga.getAggregate("COUNT")) : 0;    var actualValue = count + " devices registered in DEX";    if (count >= 100) {        return { status: "ready", actualValue: actualValue,            finding: count + " devices registered in DEX. AI diagnostic capabilities have a broad device population to analyze for patterns and anomalies." };    } else if (count >= 10) {        return { status: "needs_attention", actualValue: actualValue,            finding: "Only " + count + " devices registered in DEX (target: 100+). Expand Desktop Assistant deployment to more endpoints." };    } else {        return { status: "not_ready", actualValue: actualValue,            finding: "Only " + count + " devices registered in DEX. Deploy the DEX Desktop Assistant to managed endpoints first." };    }})()","ai_justification":"Device registration in DEX establishes the endpoint population that AI diagnostic capabilities analyze. Without sufficient registered devices, DEX AI has no data to pattern-match against for proactive issue detection and root cause analysis.","remediation_guidance":"Deploy the DEX Desktop Assistant (sn_dex_desktop) to endpoint devices. Devices must register with the DEX platform before telemetry collection can begin. Target: all managed endpoints registered.","is_manual":"0","is_clone_sensitive":"0"},{"module":"DEX","check_name":"DEX Self-Service Configuration","order":null,"check_script":"(function(checkDef, dateFilter) {    var ga = new GlideAggregate("dex_self_service_issue_config");    ga.addAggregate("COUNT");    ga.query();    var count = ga.next() ? parseInt(ga.getAggregate("COUNT")) : 0;    var actualValue = count + " DEX self-service issue configurations";    if (count >= 5) {        return { status: "ready", actualValue: actualValue,            finding: count + " self-service configurations found. Employees can use AI-guided workflows to self-diagnose and resolve common device issues." };    } else if (count >= 1) {        return { status: "needs_attention", actualValue: actualValue,            finding: "Only " + count + " self-service configuration(s) found (target: 5+). Configure additional issue types to maximize AI-guided employee deflection." };    } else {        return { status: "not_ready", actualValue: actualValue,            finding: "No DEX self-service issue configurations found. Employees cannot use AI-guided self-service workflows." };    }})()","ai_justification":"Self-service issue configurations enable employees to use AI-guided workflows to resolve their own device issues before contacting the service desk. Without these, a key DEX AI deflection capability is completely unavailable.","remediation_guidance":"Configure DEX self-service issue definitions via dex_self_service_issue_config_list.do. Self-service configurations enable employees to diagnose and resolve their own device issues using AI-guided workflows — a key deflection capability that reduces service desk volume.","is_manual":"0","is_clone_sensitive":"0"},{"module":"DEX","check_name":"DEX Score Data Availability","order":null,"check_script":"(function(checkDef, dateFilter) {
    var cutoff = new GlideDateTime();
    cutoff.addDaysUTC(-30);

    var ga = new GlideAggregate('dex_score_device_adh_score_all_agents_daily');
    ga.addQuery('sys_created_on', '>=', cutoff.getValue());
    ga.addAggregate('COUNT');
    ga.query();
    var count = ga.next() ? parseInt(ga.getAggregate('COUNT')) : 0;

    var actualValue = count + ' DEX device score records generated in last 30 days';

    if (count >= 30) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: count + ' DEX score records generated in the last 30 days. Score data is current — DEX AI skills have the analytical foundation needed for device diagnosis.'
        };
    } else if (count >= 7) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: 'Only ' + count + ' DEX score records in the last 30 days (target: 30+). Score generation may be intermittent — DEX AI diagnostic accuracy will be reduced without consistent score history.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: 'Only ' + count + ' DEX score records in the last 30 days. DEX scores are not being generated consistently — AI skills cannot perform meaningful device health analysis without score data.'
        };
    }
})","ai_justification":"DEX scores are the computed health signals that AI diagnostic skills use to identify device issues and prioritize interventions. Without score data, DEX AI cannot rank device health or trigger proactive workflows.","remediation_guidance":"Ensure DEX score generation jobs are running. DEX scores are calculated from telemetry data and used as the primary input for AI diagnostic skills. Check score generator configuration via dex_score_generator_definition and ensure scheduled jobs are active.","is_manual":"0","is_clone_sensitive":"0"},{"module":"DEX","check_name":"DEX and Now Assist Plugin Status","order":null,"check_script":"(function(checkDef, dateFilter) {
    var checkPlugin = (function checkPlugin(storeScope, pluginSource) {    var result = { found: false, version: "", table: "" };    try {        var saGR = new GlideRecord("sys_store_app");        saGR.addQuery("scope", storeScope);        saGR.setLimit(1);        saGR.query();        if (saGR.next()) {            result.found = true;            result.version = saGR.getValue("version") || "";            result.table = "sys_store_app";            return result;        }    } catch(e1) {}    if (pluginSource) {        try {            var spGR = new GlideRecord("sys_plugins");            spGR.addQuery("source", pluginSource);            spGR.addQuery("active", true);            spGR.setLimit(1);            spGR.query();            if (spGR.next()) {                result.found = true;                result.version = spGR.getValue("version") || "";                result.table = "sys_plugins";                return result;            }        } catch(e2) {}    }    return result;});

    // Check sn_dex -- may be sys_scope or sys_store_app
    var dexResult = checkPlugin("sn_dex", "sn_dex");
    if (!dexResult.found) {
        var gr = new GlideRecord("sys_scope");
        gr.addQuery("scope", "sn_dex");
        gr.addQuery("active", true);
        gr.setLimit(1);
        gr.query();
        if (gr.next()) { dexResult.found = true; dexResult.table = "sys_scope"; }
    }
    var dexActive = dexResult.found;

    // Check sn_itsm_gen_ai -- Store App confirmed
    var itsmAIResult = checkPlugin("sn_itsm_gen_ai", "sn_itsm_gen_ai");
    var itsmAIActive = itsmAIResult.found;

    var actualValue = "sn_dex: " + (dexActive ? "active" : "inactive") +
                      " | sn_itsm_gen_ai: " + (itsmAIActive ? "active (v" + itsmAIResult.version + ")" : "inactive");

    if (dexActive && itsmAIActive) {
        return { status: "ready", actualValue: actualValue,
            finding: "DEX base plugin and Now Assist for ITSM are both active. DEX AI capabilities are available." };
    } else if (dexActive && !itsmAIActive) {
        return { status: "needs_attention", actualValue: actualValue,
            finding: "DEX base plugin is active but Now Assist for ITSM (sn_itsm_gen_ai) is not. DEX AI diagnosis and agentic workflows are unavailable without sn_itsm_gen_ai." };
    } else if (!dexActive && itsmAIActive) {
        return { status: "needs_attention", actualValue: actualValue,
            finding: "Now Assist for ITSM is active but the DEX base plugin (sn_dex) is not. DEX AI capabilities require both plugins." };
    } else {
        return { status: "not_ready", actualValue: actualValue,
            finding: "Neither DEX (sn_dex) nor Now Assist for ITSM (sn_itsm_gen_ai) are active. DEX AI capabilities are completely unavailable." };
    }
})()","ai_justification":"DEX and Now Assist must both be active for AI-powered device diagnosis and agentic endpoint workflows. Without both plugins, DEX AI capabilities including conversational diagnosis and automated remediation are completely unavailable.","remediation_guidance":"Activate the base DEX plugin (sn_dex) and Now Assist for ITSM (sn_itsm_gen_ai) via the ServiceNow Store. sn_itsm_gen_ai provides the conversational AI and agentic diagnosis workflows that power DEX AI capabilities. Both are required for full DEX AI readiness.","is_manual":"0","is_clone_sensitive":"0"},{"module":"DEX","check_name":"DEX Metric Rules Configuration","order":null,"check_script":"(function(checkDef, dateFilter) {    var ga = new GlideAggregate("dex_metric_rules");    ga.addAggregate("COUNT");    ga.query();    var count = ga.next() ? parseInt(ga.getAggregate("COUNT")) : 0;    var actualValue = count + " DEX metric rules configured";    if (count >= 10) {        return { status: "ready", actualValue: actualValue,            finding: count + " metric rules configured. DEX AI has sufficient thresholds to trigger proactive investigation workflows." };    } else if (count >= 3) {        return { status: "needs_attention", actualValue: actualValue,            finding: "Only " + count + " metric rules configured (target: 10+). Limited rule coverage for DEX AI proactive investigation." };    } else {        return { status: "not_ready", actualValue: actualValue,            finding: "Fewer than 3 DEX metric rules found. DEX AI cannot proactively trigger investigation workflows without metric rules." };    }})()","ai_justification":"Metric rules define the thresholds that trigger DEX AI proactive investigation workflows. Without configured rules, DEX AI only reacts to manually created incidents, eliminating the proactive value proposition of DEX AI.","remediation_guidance":"Configure metric threshold rules via dex_metric_rules_list.do for key device and application metrics. Metric rules define the conditions that trigger DEX AI investigation workflows — without them, AI diagnosis is only reactive rather than proactive.","is_manual":"0","is_clone_sensitive":"0"},{"module":"DEX","check_name":"Application Health Monitoring","order":null,"check_script":"(function(checkDef, dateFilter) {
    var cutoff = new GlideDateTime();
    cutoff.addDaysUTC(-30);

    var ga = new GlideAggregate('dex_ci_application_device_data');
    ga.addQuery('sys_created_on', '>=', cutoff.getValue());
    ga.addAggregate('COUNT');
    ga.query();
    var count = ga.next() ? parseInt(ga.getAggregate('COUNT')) : 0;

    var actualValue = count + ' application health records collected in last 30 days';

    if (count >= 500) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: count + ' application health records in the last 30 days. DEX AI has sufficient application performance data for AI-driven diagnosis of app-related issues.'
        };
    } else if (count >= 50) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: 'Only ' + count + ' application health records in the last 30 days (target: 500+). Limited application monitoring coverage will reduce DEX AI diagnosis accuracy for app-related issues.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: 'Only ' + count + ' application health records in the last 30 days. DEX AI application diagnosis skills (Zoom, Office 365, browser performance) require active application health monitoring data.'
        };
    }
})","ai_justification":"Application health data enables DEX AI to diagnose app-specific issues such as Zoom quality and Office 365 performance. Without application monitoring, DEX AI diagnosis is limited to OS-level signals only.","remediation_guidance":"Configure application monitoring in DEX for key business applications (Zoom, Office 365, browser-based apps). Application health data is required for DEX AI skills like Zoom call quality diagnosis and application performance analysis.","is_manual":"0","is_clone_sensitive":"0"},{"module":"DEX","check_name":"DEX Survey Configuration","order":null,"check_script":"(function(checkDef, dateFilter) {
    var ga = new GlideAggregate('dex_survey_configuration');
    ga.addQuery('active', true);
    ga.addAggregate('COUNT');
    ga.query();
    var count = ga.next() ? parseInt(ga.getAggregate('COUNT')) : 0;

    var actualValue = count + ' active DEX survey configuration(s)';

    if (count >= 3) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: count + ' active DEX survey configurations. User sentiment data is being collected — DEX AI has qualitative context to complement device and application health metrics.'
        };
    } else if (count >= 1) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: 'Only ' + count + ' active DEX survey configuration(s) (target: 3+). Limited sentiment coverage — configure surveys for additional device and application scenarios.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: 'No active DEX survey configurations. User sentiment data is not being collected — DEX AI is missing the qualitative dimension needed for comprehensive digital experience analysis.'
        };
    }
})","ai_justification":"DEX survey data provides the qualitative user sentiment signal that complements device and application metrics. Without survey data, DEX AI is missing the human experience dimension needed for complete digital experience analysis.","remediation_guidance":"Configure DEX surveys via dex_survey_configuration_list.do to collect user sentiment data. Survey responses provide qualitative context that DEX AI uses alongside quantitative metrics for a complete picture of employee digital experience.","is_manual":"0","is_clone_sensitive":"0"},{"module":"DEX","check_name":"Device Metrics Coverage","order":null,"check_script":"(function(checkDef, dateFilter) {
    var cutoff = new GlideDateTime();
    cutoff.addDaysUTC(-30);

    var ga = new GlideAggregate('dex_ci_device_metrics');
    ga.addQuery('sys_created_on', '>=', cutoff.getValue());
    ga.addAggregate('COUNT');
    ga.query();
    var count = ga.next() ? parseInt(ga.getAggregate('COUNT')) : 0;

    var actualValue = count + ' device metric records collected in last 30 days';

    if (count >= 1000) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: count + ' device metric records in the last 30 days. DEX AI has rich device health signal for root cause analysis and anomaly detection.'
        };
    } else if (count >= 100) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: 'Only ' + count + ' device metric records in the last 30 days (target: 1,000+). Limited metric coverage will reduce DEX AI root cause analysis accuracy.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: 'Only ' + count + ' device metric records in the last 30 days. Insufficient device metrics for DEX AI to perform meaningful root cause analysis or anomaly detection.'
        };
    }
})","ai_justification":"Device metrics provide the granular CPU, memory, disk, and network signals that DEX AI uses for root cause analysis. Without sufficient metric coverage, AI diagnosis will misattribute or miss the actual cause of endpoint issues.","remediation_guidance":"Ensure device metric collection is configured and ACC agents are reporting device health data. Device metrics (CPU, memory, disk, network) are the raw signals DEX AI uses for root cause analysis and anomaly detection.","is_manual":"0","is_clone_sensitive":"0"},{"module":"DEX","check_name":"DEX Remedial Actions Configuration","order":null,"check_script":"(function(checkDef, dateFilter) {
    var ga = new GlideAggregate('dex_remedial_action_configuration');
    ga.addQuery('active', true);
    ga.addAggregate('COUNT');
    ga.query();
    var count = ga.next() ? parseInt(ga.getAggregate('COUNT')) : 0;

    var actualValue = count + ' active DEX remedial action configurations';

    if (count >= 5) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: count + ' active remedial action configurations. DEX AI Agents have automated resolution options available for common endpoint issues.'
        };
    } else if (count >= 1) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: 'Only ' + count + ' active remedial action configuration(s) (target: 5+). DEX AI Agent automated resolution is limited — configure additional remedial actions for common issue types.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: 'No active DEX remedial action configurations. DEX AI can diagnose issues but cannot execute automated resolutions without configured remedial actions — AI value is significantly limited.'
        };
    }
})","ai_justification":"Remedial actions give DEX AI Agents the ability to execute automated fixes, not just diagnose. Without configured remedial actions, AI can identify problems but cannot resolve them, reducing the automation value of DEX AI.","remediation_guidance":"Configure remedial actions via dex_remedial_action_configuration_list.do for common device and application issues. Remedial actions are the execution layer for DEX AI Agent automated resolution — without them, AI can diagnose but cannot act.","is_manual":"0","is_clone_sensitive":"0"},{"module":"DEX","check_name":"ACC Telemetry Data Flow","order":null,"check_script":"(function(checkDef, dateFilter) {
    var cutoff = new GlideDateTime();
    cutoff.addDaysUTC(-30);

    var ga = new GlideAggregate('dex_ci_device_data');
    ga.addQuery('sys_created_on', '>=', cutoff.getValue());
    ga.addAggregate('COUNT');
    ga.query();
    var count = ga.next() ? parseInt(ga.getAggregate('COUNT')) : 0;

    var actualValue = count + ' device data records received in last 30 days';

    if (count >= 1000) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: count + ' device telemetry records received in the last 30 days. ACC is actively collecting data — DEX AI has current endpoint context for diagnosis and analysis.'
        };
    } else if (count >= 100) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: 'Only ' + count + ' device telemetry records in the last 30 days (target: 1,000+). ACC data flow is limited — DEX AI diagnosis will have incomplete endpoint coverage.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: 'Only ' + count + ' device telemetry records in the last 30 days. Insufficient ACC data flow — DEX AI cannot perform meaningful diagnosis without active telemetry from endpoints.'
        };
    }
})","ai_justification":"ACC telemetry is the continuous data feed that powers DEX AI diagnosis. Without active telemetry flow, DEX AI cannot perform real-time endpoint health analysis or proactive anomaly detection.","remediation_guidance":"Ensure the Agent Client Collector (ACC) is installed and running on endpoint devices. ACC is the telemetry collection mechanism that feeds DEX AI — without active data flow, all AI diagnosis capabilities are non-functional. Check ACC connectivity via the DEX workspace.","is_manual":"0","is_clone_sensitive":"0"},{"module":"DEX","check_name":"Service Operations Workspace for DEX","order":null,"check_script":"(function(checkDef, dateFilter) {
    var gr = new GlideRecord('sys_scope');
    gr.addQuery('scope', 'sn_sow_itsm_cont');
    gr.addQuery('active', true);
    gr.setLimit(1);
    gr.query();
    var active = gr.next();

    if (active) {
        return {
            status: 'ready',
            actualValue: 'Service Operations Workspace (sn_sow_itsm_cont) is active',
            finding: 'Service Operations Workspace is active. DEX AI insights — including device health summaries, root cause analysis, and remediation recommendations — are surfaced in context for agents.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: 'Service Operations Workspace (sn_sow_itsm_cont) not found or inactive',
            finding: 'Service Operations Workspace is not active. DEX AI insights are not accessible in a contextually relevant interface — agents cannot act on AI recommendations without SOW.'
        };
    }
})()","ai_justification":"Service Operations Workspace is the surface where DEX AI insights are presented to agents in context. Without SOW, AI insights are generated but never seen by the people who need them.","remediation_guidance":"Activate Service Operations Workspace (sn_sow_itom) via the ServiceNow Store. SOW is the recommended interface for DEX AI insights — without it, agents interact with raw table views that lack the contextual AI recommendations DEX provides.","is_manual":"0","is_clone_sensitive":"0"}];
    },
    type: 'AROPCheckSeeder_DEX'
};
